// App.js - Facebook-Style with File Upload
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './styles.css';

const API_URL = 'http://localhost:5001/api';

function App() {
  const [currentView, setCurrentView] = useState('home');
  const [user, setUser] = useState(null);
  const [posts, setPosts] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showPostForm, setShowPostForm] = useState(false);
  const [postContent, setPostContent] = useState('');
  const [postMedia, setPostMedia] = useState(null);
  const [postMediaType, setPostMediaType] = useState('text');
  const [profilePic, setProfilePic] = useState(null);
  const [loginData, setLoginData] = useState({ email: '', password: '' });
  const [registerData, setRegisterData] = useState({ name: '', email: '', password: '' });
  const [profileData, setProfileData] = useState({ name: '', bio: '' });
  const [commentText, setCommentText] = useState({});

  // Configure axios
  const token = localStorage.getItem('token');
  if (token) {
    axios.defaults.headers.common['Authorization'] = token;
  }

  // Fetch data on load
  useEffect(() => {
    fetchPosts();
    if (token) {
      fetchUserProfile();
    }
  }, [token]);

  useEffect(() => {
    if (user?.role === 'admin') {
      fetchUsers();
    }
  }, [user]);

  const fetchPosts = async () => {
    try {
      const response = await axios.get(`${API_URL}/posts`);
      setPosts(response.data);
    } catch (error) {
      console.error('Error fetching posts:', error);
    }
  };

  const fetchUserProfile = async () => {
    try {
      const response = await axios.get(`${API_URL}/profile`);
      setUser(response.data);
      setProfileData({ name: response.data.name, bio: response.data.bio || '' });
    } catch (error) {
      console.error('Error fetching profile:', error);
    }
  };

  const fetchUsers = async () => {
    try {
      const response = await axios.get(`${API_URL}/users`);
      setUsers(response.data);
    } catch (error) {
      console.error('Error fetching users:', error);
    }
  };

  const fetchComments = async (postId) => {
    try {
      const response = await axios.get(`${API_URL}/comments/${postId}`);
      return response.data;
    } catch (error) {
      console.error('Error fetching comments:', error);
      return [];
    }
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await axios.post(`${API_URL}/login`, loginData);
      const { token, user } = response.data;
      localStorage.setItem('token', token);
      axios.defaults.headers.common['Authorization'] = token;
      setUser(user);
      setCurrentView('home');
      setShowPostForm(false);
      setLoginData({ email: '', password: '' });
    } catch (error) {
      alert('Login failed: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post(`${API_URL}/register`, registerData);
      alert('Registration successful! Please login.');
      setCurrentView('login');
      setRegisterData({ name: '', email: '', password: '' });
    } catch (error) {
      alert('Registration failed: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    delete axios.defaults.headers.common['Authorization'];
    setUser(null);
    setCurrentView('home');
    setShowPostForm(false);
  };

  const handleCreatePost = async (e) => {
    e.preventDefault();
    if (!postContent.trim()) {
      alert('Please write something to post');
      return;
    }
    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('content', postContent);
      formData.append('mediaType', postMediaType);
      if (postMedia) {
        formData.append('media', postMedia);
      }

      await axios.post(`${API_URL}/posts`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      setPostContent('');
      setPostMedia(null);
      setPostMediaType('text');
      fetchPosts();
      setShowPostForm(false);
      alert('Post created successfully!');
    } catch (error) {
      alert('Failed to create post: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleDeletePost = async (postId) => {
    if (!window.confirm('Are you sure you want to delete this post?')) return;
    try {
      await axios.delete(`${API_URL}/posts/${postId}`);
      fetchPosts();
      alert('Post deleted successfully!');
    } catch (error) {
      alert('Failed to delete post: ' + (error.response?.data?.message || 'Error'));
    }
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('name', profileData.name);
      formData.append('bio', profileData.bio);
      if (profilePic) {
        formData.append('profilePic', profilePic);
      }

      const response = await axios.put(`${API_URL}/profile`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setUser(response.data);
      alert('Profile updated successfully!');
      setCurrentView('profile');
    } catch (error) {
      alert('Failed to update profile: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleUserStatus = async (userId, currentStatus) => {
    try {
      await axios.put(`${API_URL}/users/${userId}/status`, { isActive: !currentStatus });
      fetchUsers();
      alert(`User ${!currentStatus ? 'activated' : 'deactivated'} successfully!`);
    } catch (error) {
      alert('Failed to update user status');
    }
  };

  const handleAddComment = async (postId) => {
    if (!commentText[postId]?.trim()) return;
    try {
      await axios.post(`${API_URL}/comments/${postId}`, { content: commentText[postId] });
      setCommentText({ ...commentText, [postId]: '' });
      const updatedComments = await fetchComments(postId);
      setPosts(posts.map(post => 
        post._id === postId 
          ? { ...post, comments: updatedComments }
          : post
      ));
    } catch (error) {
      alert('Failed to add comment');
    }
  };

  const handleDeleteComment = async (commentId, postId) => {
    if (!window.confirm('Delete this comment?')) return;
    try {
      await axios.delete(`${API_URL}/comments/${commentId}`);
      const updatedComments = await fetchComments(postId);
      setPosts(posts.map(post => 
        post._id === postId 
          ? { ...post, comments: updatedComments }
          : post
      ));
    } catch (error) {
      alert('Failed to delete comment');
    }
  };

  // Handle file selection for post
  const handleMediaSelect = (e, type) => {
    const file = e.target.files[0];
    if (file) {
      setPostMedia(file);
      setPostMediaType(type);
    }
  };

  // Trigger file input click
  const triggerFileInput = (type) => {
    document.getElementById(`${type}-input`).click();
  };

  // Reaction System
  const [postReactions, setPostReactions] = useState({});

  const handleReaction = (postId, reactionType) => {
    setPostReactions(prev => ({
      ...prev,
      [postId]: {
        type: reactionType,
        count: (prev[postId]?.count || 0) + 1
      }
    }));
  };

  const getReactionIcon = (reactionType) => {
    switch(reactionType) {
      case 'like': return '­¤æŹ';
      case 'love': return 'ŌØż’ĖÅ';
      case 'haha': return '­¤śé';
      case 'wow': return '­¤ś«';
      case 'sad': return '­¤śó';
      case 'angry': return '­¤śĀ';
      default: return '­¤æŹ';
    }
  };

  // ============= NAVIGATION MENU =============
  const renderNav = () => {
    if (!user) {
      return (
        <header>
          <h1>
            <img src="/images/Hot-Wheels-Emblem.png" alt="Hot Wheels" width="60" />
            Hot Wheels Blog
          </h1>
          <nav>
            <ul>
              <li><button onClick={() => { setCurrentView('home'); setShowPostForm(false); }} className={currentView === 'home' ? 'active' : ''}>Home</button></li>
              <li><button onClick={() => setCurrentView('about')} className={currentView === 'about' ? 'active' : ''}>About</button></li>
              <li><button onClick={() => setCurrentView('contact')} className={currentView === 'contact' ? 'active' : ''}>Contact</button></li>
              <li><button onClick={() => setCurrentView('register')} className={currentView === 'register' ? 'active' : ''}>Register</button></li>
              <li><button onClick={() => setCurrentView('login')} className={currentView === 'login' ? 'active' : ''}>Login</button></li>
            </ul>
          </nav>
        </header>
      );
    } else if (user.role === 'admin') {
      return (
        <header>
          <h1>
            <img src="/images/Hot-Wheels-Emblem.png" alt="Hot Wheels" width="60" />
            Hot Wheels Blog - Admin
          </h1>
          <nav>
            <ul>
              <li><button onClick={() => { setCurrentView('home'); setShowPostForm(false); }} className={currentView === 'home' ? 'active' : ''}>Home</button></li>
              <li><button onClick={() => setCurrentView('about')} className={currentView === 'about' ? 'active' : ''}>About</button></li>
              <li><button onClick={() => setCurrentView('profile')} className={currentView === 'profile' ? 'active' : ''}>Profile</button></li>
              <li><button onClick={() => setCurrentView('admin')} className={currentView === 'admin' ? 'active' : ''}>Admin</button></li>
              <li><button onClick={handleLogout}>Logout</button></li>
              <li><span style={{ color: '#ff9800' }}>Welcome, {user.name} (Admin)</span></li>
            </ul>
          </nav>
        </header>
      );
    } else {
      return (
        <header>
          <h1>
            <img src="/images/Hot-Wheels-Emblem.png" alt="Hot Wheels" width="60" />
            Hot Wheels Blog
          </h1>
          <nav>
            <ul>
