  // Quiz Component
  const QuizComponent = () => {
    const [currentQuestion, setCurrentQuestion] = useState(0);
    const [score, setScore] = useState(0);
    const [showResult, setShowResult] = useState(false);
    const [selectedAnswer, setSelectedAnswer] = useState(null);

    const questions = [
      {
        question: "What year was Hot Wheels founded?",
        options: ["1968", "1975", "1982", "1990"],
        correct: 0
      },
      {
        question: "What was the first Hot Wheels car ever made?",
        options: ["Twin Mill", "Custom Camaro", "Sweet 16", "Bone Shaker"],
        correct: 1
      },
      {
        question: "Which company manufactures Hot Wheels?",
        options: ["Hasbro", "Lego", "Mattel", "Bandai"],
        correct: 2
      },
      {
        question: "What color is the famous 'Treasure Hunt' logo?",
        options: ["Red", "Blue", "Green", "Yellow"],
        correct: 0
      }
    ];

    const handleAnswer = (selectedIdx) => {
      setSelectedAnswer(selectedIdx);
    };

    const handleNext = () => {
      if (selectedAnswer === questions[currentQuestion].correct) {
        setScore(score + 1);
      }
      setSelectedAnswer(null);
      if (currentQuestion + 1 < questions.length) {
        setCurrentQuestion(currentQuestion + 1);
      } else {
        setShowResult(true);
      }
    };

    if (showResult) {
      return (
        <div className="quiz-complete">
          <h3>Quiz Complete!</h3>
          <p>Your score: {score} out of {questions.length}</p>
          <p>{score === questions.length ? "Perfect! You're a Hot Wheels expert!" : "Good try! Keep collecting!"}</p>
        </div>
      );
    }

    return (
      <div>
        <h3 id="quizQuestion">{questions[currentQuestion].question}</h3>
        <div className="options">
          {questions[currentQuestion].options.map((option, idx) => (
            <div
              key={idx}
              className={`option ${selectedAnswer === idx ? 'selected' : ''}`}
              onClick={() => handleAnswer(idx)}
            >
              {option}
            </div>
          ))}
        </div>
        <button onClick={handleNext} disabled={selectedAnswer === null}>
          {currentQuestion + 1 === questions.length ? 'Finish' : 'Next'}
        </button>
      </div>
    );
  };

